def get_cal_base_task_list():
    code_date_dict = CODE_DATE_DICT
    base_task_list = [(code, date) for code, date_list in code_date_dict.items() for date in date_list]
    # outlier_task_list = get_cal_outlier_test_task_list(is_order_factor=is_order_factor)
    # task_list = sorted(set(base_task_list).union(outlier_task_list))
    task_list = sorted(set(base_task_list))
    return task_list


def get_cal_cb_task_list(type='CB', is_order_factor=False):
    import pickle
    type = type.lower()
    if type == 'cb':
        with open('/data/user/017023/share/CB_Sample/finalList.pkl', 'rb') as f:
            code_date_dict = pickle.load(f)
    elif type == 'stock':
        with open('/data/user/017023/share/CB_Sample/finalStockList.pkl', 'rb') as f:
            code_date_dict = pickle.load(f)
    else:
        print('Unknowned Type.')
        return
    if is_order_factor:
        code_date_dict = {i: j for i, j in code_date_dict.items() if i.endswith('SZ')}
    base_task_list = [(code, date) for code, date_list in code_date_dict.items() for date in date_list]
    task_list = sorted(set(base_task_list))
    return task_list
